/* CityRail Core: Event Bus */
(function (window) {
  'use strict';

  const listeners = new Map();
  const history = [];
  const MAX_HISTORY = 200;

  function record(type, payload) {
    history.push({ type, payload, at: Date.now() });
    if (history.length > MAX_HISTORY) history.shift();
  }

  function on(type, handler) {
    if (typeof handler !== 'function') throw new TypeError('CityRail.events.on requires a function handler');
    if (!listeners.has(type)) listeners.set(type, new Set());
    listeners.get(type).add(handler);
    return function off() { listeners.get(type)?.delete(handler); };
  }

  function once(type, handler) {
    const off = on(type, function onceHandler(payload) {
      off();
      handler(payload);
    });
    return off;
  }

  function emit(type, payload) {
    record(type, payload);
    const set = listeners.get(type);
    if (set) {
      Array.from(set).forEach(function (handler) {
        try { handler(payload); }
        catch (error) { console.error('[CityRail.events] listener failed:', type, error); }
      });
    }
    try {
      window.dispatchEvent(new CustomEvent('cityrail:' + type, { detail: payload }));
    } catch (error) {
      // CustomEvent can fail in very old browsers; the internal bus still works.
    }
  }

  function getHistory() { return history.slice(); }

  window.CityRail = window.CityRail || {};
  window.CityRail.events = { on, once, emit, getHistory };
})(window);

