// ===== SETTINGS OVERLAY =====
const btnSettings = document.getElementById('btn-settings');
const settingsOverlay = document.getElementById('settings-overlay');
try { state.showOpenRailway = (localStorage.getItem('cityrail_orm_overlay') === '1'); } catch(e) { state.showOpenRailway = false; }
syncOpenRailwayBasemapCycle();

function openSettings() {
  updateSettingsUI();
  settingsOverlay.classList.remove('hidden');
  btnSettings.classList.add('active');
}
function closeSettings() {
  settingsOverlay.classList.add('hidden');
  btnSettings.classList.remove('active');
}
function toggleSettings() {
  if (settingsOverlay.classList.contains('hidden')) openSettings();
  else closeSettings();
}

function getOpenRailwayOverlay() {
  if (typeof L === 'undefined' || typeof map === 'undefined' || !map) return null;
  if (!window.__cityrailOrmOverlay) {
    window.__cityrailOrmOverlay = L.tileLayer('https://{s}.tiles.openrailwaymap.org/standard/{z}/{x}/{y}.png', {
      attribution: '&copy; OpenStreetMap contributors & OpenRailwayMap',
      subdomains: 'abc', maxZoom: 19, opacity: 0.72, updateWhenZooming: false, updateWhenIdle: true, keepBuffer: 3
    });
  }
  return window.__cityrailOrmOverlay;
}
function setOpenRailwayEnabled(on) {
  state.showOpenRailway = !!on;
  const layer = getOpenRailwayOverlay();
  if (layer && typeof map !== 'undefined' && map) {
    if (on && !map.hasLayer(layer)) layer.addTo(map);
    if (!on && map.hasLayer(layer)) map.removeLayer(layer);
  }
  try { localStorage.setItem('cityrail_orm_overlay', on ? '1' : '0'); } catch(e) {}
}
function syncOpenRailwayBasemapCycle() {
  // OpenRailwayMap 是覆盖图层，不参与底图循环。
  try {
    if (typeof layerKeys !== 'undefined' && Array.isArray(layerKeys)) {
      for (let i = layerKeys.length - 1; i >= 0; i--) {
        if (String(layerKeys[i]).toLowerCase() === 'openrailway' || String(layerKeys[i]).toLowerCase() === 'gray') layerKeys.splice(i, 1);
      }
      if (typeof currentLayerIdx !== 'undefined' && currentLayerIdx >= layerKeys.length) currentLayerIdx = 0;
    }
    if (typeof tileLayers !== 'undefined' && tileLayers.openrailway) {
      try { if (typeof map !== 'undefined' && map.hasLayer(tileLayers.openrailway)) map.removeLayer(tileLayers.openrailway); } catch(e) {}
      delete tileLayers.openrailway;
    }
  } catch(e) {}
}

function updateSettingsUI() {
  syncOpenRailwayBasemapCycle();
  ['trains','labels','openrailway'].forEach(key => {
    const el = document.getElementById(key === 'openrailway' ? 'st-openrailway' : `st-${key}`);
    if (!el) return;
    const on = key === 'trains' ? state.showTrains : (key === 'labels' ? state.showLabels : !!state.showOpenRailway);
    el.className = 'settings-toggle ' + (on ? 'on' : 'off');
  });
}

btnSettings.addEventListener('click', (e) => { e.stopPropagation(); toggleSettings(); });

// Toggle rows
settingsOverlay.querySelectorAll('.settings-row').forEach(row => {
  row.addEventListener('click', () => {
    const setting = row.dataset.setting;
    if (setting === 'trains') {
      state.showTrains = !state.showTrains;
      if (state.showTrains) { if (state.trains.length === 0) initAllTrains(); }
      else { Object.values(trainMarkers).forEach(m => map.removeLayer(m)); trainMarkers = {}; }
    } else if (setting === 'labels') {
      state.showLabels = !state.showLabels;
      const mapEl = document.getElementById('map');
      if (state.showLabels) mapEl.classList.remove('hide-labels');
      else mapEl.classList.add('hide-labels');
    } else if (setting === 'openrailway') {
      setOpenRailwayEnabled(!state.showOpenRailway);
    }
    updateSettingsUI();
    saveState();
  });
});

