// ==================== NEW LINE DRAW MODE ====================
let drawNewLine = null; // { name, color, tempStations: [{id,lat,lng,name}], tempWaypoints: [{id,lat,lng,segIdx}], previewLine, waypointMarkers: [L.circleMarker] }

// Open new line dialog
document.getElementById('btn-new-line').addEventListener('click', () => {
  document.getElementById('new-line-dialog-overlay').classList.remove('hidden');
  document.getElementById('new-line-name').value = '';
  document.getElementById('new-line-color').value = '#4fc3f7';
  document.getElementById('new-line-name').focus();
});

// Close dialog
document.getElementById('new-line-cancel').addEventListener('click', () => {
  document.getElementById('new-line-dialog-overlay').classList.add('hidden');
});
// Enter key to start drawing
document.getElementById('new-line-name').addEventListener('keydown', (e) => {
  if (e.key === 'Enter') document.getElementById('new-line-start').click();
  if (e.key === 'Escape') document.getElementById('new-line-cancel').click();
});
document.getElementById('new-line-dialog-overlay').addEventListener('click', (e) => {
  if (e.target === e.currentTarget) document.getElementById('new-line-dialog-overlay').classList.add('hidden');
});

// Start drawing
document.getElementById('new-line-start').addEventListener('click', () => {
  const name = document.getElementById('new-line-name').value.trim();
  if (!name) { document.getElementById('new-line-name').focus(); return; }
  const color = document.getElementById('new-line-color').value;
  document.getElementById('new-line-dialog-overlay').classList.add('hidden');

  drawNewLine = { name, color, tempStations: [], tempWaypoints: [], previewLine: null, waypointMarkers: [] };
  document.getElementById('draw-line-indicator').classList.remove('hidden');
  document.getElementById('draw-line-hint').textContent = '▸ 左键放置车站 · 右键放置节点（仅改走向）';
  document.getElementById('draw-tooltip').classList.remove('hidden');
  map.getContainer().style.cursor = 'crosshair';
});

// Cancel drawing
function cancelDrawLine() {
  if (drawNewLine && drawNewLine.tempStations.length > 0) {
    // When extending/branching, skip the starting station (it's an existing station)
    const stationsToRemove = drawNewLine.startFromStation
      ? drawNewLine.tempStations.slice(1)
      : drawNewLine.tempStations;
    stationsToRemove.forEach(s => {
      state.stations = state.stations.filter(ss => ss.id !== s.id);
      removeStationPolygons(s.id);
    });
    if (stationsToRemove.length > 0) {
      invalidateFlowCache();
      updateUI();
      saveState();
    }
  }
  if (drawNewLine && drawNewLine.previewLine) {
    map.removeLayer(drawNewLine.previewLine);
  }
  // Remove waypoint markers
  if (drawNewLine && drawNewLine.waypointMarkers) {
    drawNewLine.waypointMarkers.forEach(m => map.removeLayer(m));
  }
  drawNewLine = null;
  document.getElementById('draw-line-indicator').classList.add('hidden');
  document.getElementById('draw-tooltip').classList.add('hidden');
  map.getContainer().style.cursor = '';
}

document.getElementById('draw-line-cancel').addEventListener('click', cancelDrawLine);

// Finish drawing
document.getElementById('draw-line-finish').addEventListener('click', () => {
  if (!drawNewLine || drawNewLine.tempStations.length < 2) {
    cancelDrawLine();
    return;
  }

  // Clean up preview & markers
  if (drawNewLine.previewLine) map.removeLayer(drawNewLine.previewLine);
  if (drawNewLine.waypointMarkers) drawNewLine.waypointMarkers.forEach(m => map.removeLayer(m));

  // ---- CASE 1: Extend existing line ----
  if (drawNewLine.extendLineId) {
    const line = state.lines.find(l => l.id === drawNewLine.extendLineId);
    if (!line) { drawNewLine = null; resetDrawUI(); return; }

    const newStationIds = drawNewLine.tempStations.slice(1).map(s => s.id);
    const startIdx = drawNewLine.extendFromStart ? 0 : line.stationIds.length - 1;
    const newCount = newStationIds.length;

    if (drawNewLine.extendFromStart) {
      // Prepend in reverse order
      const reversedIds = [...newStationIds].reverse();
      line.stationIds = [...reversedIds, ...line.stationIds];
      // 既有线路从头部延长时，原有所有节点所属区间整体后移。
      // 不后移会导致旧节点挂错区间，线路几何和列车路径都会错。
      if (Array.isArray(line.waypoints)) {
        line.waypoints.forEach(w => { w.segIdx += newCount; });
      } else {
        line.waypoints = [];
      }
      // Map waypoints: draw segIdx K → new segIdx (newCount - 1 - K)
      (drawNewLine.tempWaypoints || []).forEach(wp => {
        if (wp.segIdx >= 0 && wp.segIdx < newCount) {
          line.waypoints.push({
            id: wp.id, lat: wp.lat, lng: wp.lng,
            segIdx: newCount - 1 - wp.segIdx,
            order: line.waypoints.filter(w => w.segIdx === newCount - 1 - wp.segIdx).length
          });
        }
      });
    } else {
      // Append
      const baseSeg = line.stationIds.length - 1;
      line.stationIds = [...line.stationIds, ...newStationIds];
      (drawNewLine.tempWaypoints || []).forEach(wp => {
        if (wp.segIdx >= 0 && wp.segIdx < newCount) {
          line.waypoints.push({
            id: wp.id, lat: wp.lat, lng: wp.lng,
            segIdx: baseSeg + wp.segIdx,
            order: line.waypoints.filter(w => w.segIdx === baseSeg + wp.segIdx).length
          });
        }
      });
    }

    normalizeLineWaypoints(line, 'extendExistingLine');
    drawNewLine = null;
    resetDrawUI();
    rebuildLineTopology(line, 'extendExistingLine');

    // 异步启动模拟
    setTimeout(() => {
      runSimulation();
      openLineConfig(line.id);
    }, 0);
    return;
  }

  // ---- CASE 2: Branch from existing line ----
  if (drawNewLine.parentLineId) {
    const stationIds = drawNewLine.tempStations.map(s => s.id);
    const waypoints = (drawNewLine.tempWaypoints || [])
      .filter(w => w.segIdx >= 0 && w.segIdx < stationIds.length - 1)
      .map((w, i) => ({ id: w.id, lat: w.lat, lng: w.lng, segIdx: w.segIdx, order: i }));

    const line = {
      id: genId(),
      name: drawNewLine.name,
      color: drawNewLine.color,
      stationIds,
      waypoints,
      trainType: drawNewLine.branchTrainType || 'A',
      cars: drawNewLine.branchCars || 6,
      speed: drawNewLine.branchSpeed || 80,
      offPeakHeadwayMin: 10,
      normalHeadwayMin: 6,
      peakHeadwayMin: 3,
      parentLineId: drawNewLine.parentLineId, // 记录所属主线
      branchTransferPenalty: drawNewLine.branchTransferPenalty || 2, // 支线与主线换乘时间(分钟)
      pathMode: 'ordered',
    };
    state.lines.push(line);

    // Re-render shared station (stationIds[0]) to show it on both lines
    const sharedId = stationIds[0];
    reRenderStationsOnLine(line);
    // Also re-render the parent line's stations at the shared point
    const parentLine = state.lines.find(l => l.id === drawNewLine.parentLineId);
    if (parentLine) reRenderStationsOnLine(parentLine);

    renderLine(line);
    drawNewLine = null;
    resetDrawUI();
    invalidateFlowCache();
    updateUI();
    saveState();
    initAllTrains();

    // 异步重算
    setTimeout(() => {
      runSimulation();
      openLineConfig(line.id);
    }, 0);
    return;
  }

  // ---- CASE 3: Normal new line ----
  const stationIds = drawNewLine.tempStations.map(s => s.id);
  const lineName = drawNewLine.name;
  const lineColor = drawNewLine.color;
  const waypoints = (drawNewLine.tempWaypoints || [])
    .filter(w => w.segIdx >= 0 && w.segIdx < stationIds.length - 1)
    .map((w, i) => ({ id: w.id, lat: w.lat, lng: w.lng, segIdx: w.segIdx, order: i }));

  drawNewLine = null;

  const line = {
    id: genId(),
    name: lineName,
    color: lineColor,
    stationIds,
    waypoints,
    trainType: 'A',
    cars: 6,
    speed: 80,
    offPeakHeadwayMin: 10,
    normalHeadwayMin: 6,
    peakHeadwayMin: 3,
    pathMode: 'ordered',
  };
  state.lines.push(line);
  reRenderStationsOnLine(line);
  renderLine(line);
  invalidateFlowCache();
  updateUI();
  saveState();

  resetDrawUI();
  initAllTrains();

  // 异步重算
  setTimeout(() => {
    runSimulation();
    openLineConfig(line.id);
  }, 0);
});

// Helper: reset draw mode UI
function resetDrawUI() {
  document.getElementById('draw-line-indicator').classList.add('hidden');
  document.getElementById('draw-tooltip').classList.add('hidden');
  map.getContainer().style.cursor = '';
}

// Helper: re-render all stations on a line
function reRenderStationsOnLine(line) {
  line.stationIds.forEach(sid => {
    const s = state.stations.find(ss => ss.id === sid);
    if (s) {
      removeStationPolygons(sid);
      renderStation(s);
    }
  });
}

// Map click handler for drawing new line — LEFT CLICK = station
map.on('click', (e) => {
  if (!drawNewLine) return;
  if (triangleClicked) return;
  const { lat, lng } = e.latlng;

  // Create station
  const usedNames = state.stations.map(s => s.name);
  const rank = state.stations.length + 1;
  const totalPseudo = state.stations.length + 1;
  const population = populationByRank(rank, totalPseudo);
  const station = {
    id: genId(),
    name: getRandomName(usedNames),
    lat, lng,
    population,
    zoneType: inferZoneTypeByArea(lat, lng),
  };
  state.stations.push(station);
  renderStation(station);
  drawNewLine.tempStations.push(station);

  // 检查是否需要建立虚拟换乘（距离1000m内的已有车站）
  checkAndPromptVirtualTransfer(station.id);

  // Update preview line (including waypoints between stations)
  updateDrawPreview();

  // Update hint
  const cnt = drawNewLine.tempStations.length;
  const wpCnt = drawNewLine.tempWaypoints.length;
  document.getElementById('draw-line-hint').textContent =
    `▸ 已放置 ${cnt} 个车站${wpCnt > 0 ? ' · ' + wpCnt + ' 个节点' : ''} · 继续点击或点「完成」`;

  invalidateFlowCache();
  updateUI();
  saveState();
});

// Map right-click handler for drawing new line — RIGHT CLICK = waypoint
map.on('contextmenu', (e) => {
  if (!drawNewLine) return;
  L.DomEvent.preventDefault(e);
  const { lat, lng } = e.latlng;

  // Determine segment: between last station and future next station
  const segIdx = Math.max(0, drawNewLine.tempStations.length - 1);
  const wp = { id: genId(), lat, lng, segIdx };
  drawNewLine.tempWaypoints.push(wp);

  // Show a small marker for the waypoint
  const marker = L.circleMarker([lat, lng], {
    radius: 4,
    color: '#ffab40',
    fillColor: '#ffab40',
    fillOpacity: 0.8,
    weight: 2,
    interactive: false,
  }).addTo(map);
  drawNewLine.waypointMarkers.push(marker);

  // Update preview line
  updateDrawPreview();

  // Update hint
  const cnt = drawNewLine.tempStations.length;
  const wpCnt = drawNewLine.tempWaypoints.length;
  document.getElementById('draw-line-hint').textContent =
    `▸ 已放置 ${cnt} 个车站 · ${wpCnt} 个节点 · 继续点击或点「完成」`;
});

// Helper: rebuild preview polyline from stations + waypoints
function updateDrawPreview() {
  if (!drawNewLine) return;
  if (drawNewLine.previewLine) {
    map.removeLayer(drawNewLine.previewLine);
    drawNewLine.previewLine = null;
  }

  // Build ordered points: station 0 → [waypoints seg0] → station 1 → [waypoints seg1] → ...
  const pts = [];
  for (let i = 0; i < drawNewLine.tempStations.length; i++) {
    pts.push([drawNewLine.tempStations[i].lat, drawNewLine.tempStations[i].lng]);
    if (i < drawNewLine.tempStations.length - 1) {
      const segWps = drawNewLine.tempWaypoints
        .filter(w => w.segIdx === i)
        .sort((a, b) => drawNewLine.tempWaypoints.indexOf(a) - drawNewLine.tempWaypoints.indexOf(b));
      segWps.forEach(w => pts.push([w.lat, w.lng]));
    }
  }

  if (pts.length >= 2) {
    drawNewLine.previewLine = L.polyline(pts, {
      color: drawNewLine.color,
      weight: 3,
      opacity: 0.7,
      dashArray: '10 6',
      lineCap: 'round',
    }).addTo(map);
  }
}

