document.getElementById('sd-btn-move').addEventListener('click', () => {
  if (!stationDetailId) return;
  const polygon = stationMarkers[stationDetailId];
  if (!polygon) return;
  const btn = document.getElementById('sd-btn-move');
  const hint = document.getElementById('sd-move-hint');
  const picker = document.getElementById('sd-line-picker');
  const isActive = btn.classList.contains('active-action');
  if (isActive) {
    // Disable move mode
    btn.classList.remove('active-action');
    btn.textContent = '移动车站';
    hint.style.display = 'none';
    moveLineId = null;
    if (picker) picker.style.display = 'none';
    const allPolys = stationTransferPolygons[stationDetailId] || [];
    allPolys.forEach(p => { if (p._baseStyle) p.setStyle(p._baseStyle); });
  } else {
    // Check if transfer station
    const station = state.stations.find(s => s.id === stationDetailId);
    const lines = station ? getStationLines(station.id) : [];
    if (lines.length > 1) {
      // Show line picker for transfer stations
      showLinePicker(station, lines);
    } else {
      // Non-transfer: enable move directly
      moveLineId = lines.length > 0 ? lines[0].id : null;
      enterMoveMode(polygon, btn, hint, picker);
    }
  }
});

function showLinePicker(station, lines) {
  const picker = document.getElementById('sd-line-picker');
  const btnsContainer = document.getElementById('sd-line-picker-btns');
  if (!picker || !btnsContainer) return;
  // Build line picker buttons
  btnsContainer.innerHTML = lines.map(line => {
    return `<button class="sd-line-pick-btn" data-line-id="${line.id}"
      style="border-color:${line.color};color:${line.color}">${line.name}</button>`;
  }).join('');
  picker.style.display = 'block';
  // Add click handlers
  btnsContainer.querySelectorAll('.sd-line-pick-btn').forEach(btn => {
    btn.addEventListener('click', (e) => {
      e.stopPropagation();
      const lineId = btn.getAttribute('data-line-id');
      moveLineId = lineId;
      picker.style.display = 'none';
      // Find the matching polygon and enter move mode
      const allPolys = stationTransferPolygons[station.id] || [];
      const targetPoly = allPolys.find(p => p._lineId === lineId) || allPolys[0];
      const moveBtn = document.getElementById('sd-btn-move');
      const moveHint = document.getElementById('sd-move-hint');
      enterMoveMode(targetPoly, moveBtn, moveHint, picker);
    });
  });
}

function enterMoveMode(polygon, btn, hint, picker) {
  if (picker) picker.style.display = 'none';
  btn.classList.add('active-action');
  btn.textContent = '拖动中...';
  hint.style.display = 'block';
  polygon.setStyle({ fillOpacity: 0.55, weight: 2, color: '#fff', opacity: 1 });
  // Start the drag session immediately. Historical CSS and SVG ownership patches
  // can swallow the polygon mousedown event, leaving the move button active but
  // never assigning dragStationId. Map mousemove now has one reliable owner.
  dragStationId = stationDetailId;
  dragLineId = moveLineId || polygon._lineId || null;
  dragPolygon = polygon;
  map.dragging.disable();
  map.getContainer().style.cursor = 'grabbing';
}

window.CityRailStationDragCore = {
  version: 'v145-drag-core',
  active: () => !!dragStationId,
  stationId: () => dragStationId,
  lineId: () => dragLineId,
  finish: save => finishStationDrag(save !== false)
};

document.getElementById('sd-btn-delete').addEventListener('click', () => {
  if (!stationDetailId) return;
  const station = state.stations.find(s => s.id === stationDetailId);
  if (!station) return;
  if (!confirm(`确定删除站点「${station.name}」吗？相关线路区段也会被移除。`)) return;

  // Remove from lines. v88：如果删除的是终点站，同时删除终点与上一个车站之间的节点/区间；
  // 如果删除中间站，则删除前后相邻区间节点并重建拓扑，避免孤儿 waypoint 导致线路乱绕。
  state.lines.forEach(line => {
    const oldIdx = line.stationIds.indexOf(stationDetailId);
    if (oldIdx < 0) return;
    const oldLen = line.stationIds.length;
    if (Array.isArray(line.waypoints)) {
      if (oldIdx === 0) {
        line.waypoints = line.waypoints
          .filter(w => Number(w.segIdx) !== 0)
          .map(w => Object.assign({}, w, { segIdx: Math.max(0, Number(w.segIdx) - 1) }));
      } else if (oldIdx === oldLen - 1) {
        line.waypoints = line.waypoints.filter(w => Number(w.segIdx) !== oldIdx - 1);
      } else {
        line.waypoints = line.waypoints
          .filter(w => Number(w.segIdx) !== oldIdx - 1 && Number(w.segIdx) !== oldIdx)
          .map(w => Object.assign({}, w, { segIdx: Number(w.segIdx) > oldIdx ? Number(w.segIdx) - 1 : Number(w.segIdx) }));
      }
    }
    line.stationIds = line.stationIds.filter(sid => sid !== stationDetailId);
    if (line.stationIds.length >= 2) normalizeLineWaypoints(line, 'deleteStationDetail');
  });

  removeStationPolygons(stationDetailId);
  state.stations = state.stations.filter(s => s.id !== stationDetailId);
  removeDegenerateLinesAndExclusiveStations('deleteStationDetail');
  invalidateLineNodesCache();
  state.lines.forEach(line => { try { normalizeLineWaypoints(line, 'deleteStationDetail-refresh'); line._topologyVersion = (Number(line._topologyVersion)||0)+1; } catch(e) {} });
  refreshAllLines();
  refreshAllStations();
  closeStationDetail();

  // 异步重算：不阻塞 UI
  setTimeout(() => {
    invalidateFlowCache();
    updateUI();
    runSimulation();
    saveState();
    initAllTrains();
  }, 0);
});

// ==================== NAVIGATION ====================
let navRouteLayer = null;
const TRANSFER_PENALTY_MIN = 5; // 默认换乘惩罚：5分钟等效
const VT_LINE_ID = '__virtual_transfer__'; // 虚拟换乘边的特殊 lineId

// 虚拟换乘类型定义：距离范围（米）→ 类型名称 → 罚时（分钟）
const VT_TYPES = [
  { maxDist: 1000, minDist: 500, type: 'virtual',       label: '虚拟换乘',        penalty: 10 },
  { maxDist: 500,  minDist: 300, type: 'long_corridor', label: '长通道换乘',      penalty: 6 },
  { maxDist: 300,  minDist: 100, type: 'short_corridor',label: '短通道换乘',      penalty: 3 },
  { maxDist: 100,  minDist: 0,   type: 'platform_same', label: '节点换乘/同台换乘', penalty: 1.5 },
];

// 根据距离(米)获取对应的换乘类型配置，超出1000m返回null
function getVTTypeByDistance(distM) {
  for (const t of VT_TYPES) {
    if (distM > t.minDist && distM <= t.maxDist) return t;
  }
  if (distM <= t.maxDist) return t;
  return null;
}

// 检查两站是否已有虚拟换乘关系
function findVirtualTransfer(sidA, sidB) {
  return state.virtualTransfers.find(vt =>
    (vt.stationA === sidA && vt.stationB === sidB) ||
    (vt.stationA === sidB && vt.stationB === sidA)
  );
}

// ── 虚拟换乘弹窗（Apple 风格模态框）──
const vtOverlay  = document.getElementById('vt-overlay');
const vtIcon     = document.getElementById('vt-icon');
const vtTitle    = document.getElementById('vt-title');
const vtSubtitle = document.getElementById('vt-subtitle');
const vtStA      = document.getElementById('vt-st-a');
const vtStB      = document.getElementById('vt-st-b');
const vtDistNum  = document.getElementById('vt-dist-num');
const vtTypeBadge = document.getElementById('vt-type-badge');
const vtPenaltyHint = document.getElementById('vt-penalty-hint');
const vtBtnCancel = document.getElementById('vt-btn-cancel');
const vtBtnConfirm= document.getElementById('vt-btn-confirm');

let _vtResolve = null;

function showVTPrompt({ stNameA, stNameB, distM, vtType, mode = 'create' }) {
  return new Promise(resolve => {
    _vtResolve = resolve;

    // 标题
    if (mode === 'remove') {
      vtTitle.textContent = '取消换乘关系';
      vtSubtitle.textContent = '两站距离已超出虚拟换乘上限';
    } else if (mode === 'upgrade') {
      vtTitle.textContent = '升级换乘方式';
      vtSubtitle.textContent = '距离变化，建议调整换乘类型';
    } else {
      vtTitle.textContent = '设置换乘';
      vtSubtitle.textContent = '检测到两站距离较近，可设为换乘站';
    }

    // 站名
    vtStA.textContent = stNameA;
    vtStB.textContent = stNameB;

    // 距离
    vtDistNum.textContent = Math.round(distM);

    // 类型徽章 & 提示
    if (mode === 'remove') {
      vtTypeBadge.className = 'vt-type-badge virtual';
      vtTypeBadge.innerHTML = '<span>超出范围</span>';
      vtPenaltyHint.textContent = `距离 ${Math.round(distM)}m > 上限 1000m`;
    } else {
      vtTypeBadge.className = 'vt-type-badge ' + vtType.type;
      vtTypeBadge.textContent = vtType.label;
      vtPenaltyHint.textContent =
        mode === 'upgrade'
          ? `原范围上限 ${VT_TYPES.find(t=>t.type===vtType.type ? false : undefined) || ''}m → 罚时 ${vtType.penalty} 分钟`
          : `确认后两站为换乘站，换乘罚时 ${vtType.penalty} 分钟`;
    }

    // 按钮文字
    if (mode === 'remove') {
      vtBtnConfirm.textContent = '取消换乘';
    } else if (mode === 'upgrade') {
      vtBtnConfirm.textContent = '确认升级';
    } else {
      vtBtnConfirm.textContent = '确认设置';
    }
    vtBtnCancel.textContent = '取消';

    // 显示
    vtOverlay.classList.remove('hidden');

    // 入场动画
    requestAnimationFrame(() => {
      const panel = document.getElementById('vt-panel');
      panel.style.opacity = '0';
      panel.style.transform = 'scale(0.92) translateY(12px)';
      panel.style.transition = 'opacity 0.28s ease, transform 0.28s cubic-bezier(0.34,1.56,0.64,1)';
      requestAnimationFrame(() => {
        panel.style.opacity = '1';
        panel.style.transform = 'scale(1) translateY(0)';
      });
    });
  });
}

function hideVTModal(confirmed) {
  const panel = document.getElementById('vt-panel');
  panel.style.transition = 'opacity 0.18s ease, transform 0.2s ease';
  panel.style.opacity = '0';
  panel.style.transform = 'scale(0.94) translateY(8px)';
  // 先 resolve 让调用方拿到结果（弹窗已开始消失，UI 已响应）
  if (_vtResolve) { _vtResolve(confirmed); _vtResolve = null; }
  setTimeout(() => {
    vtOverlay.classList.add('hidden');
    panel.style.transition = '';
    panel.style.opacity = '';
    panel.style.transform = '';
  }, 200);
}

vtBtnCancel.addEventListener('click', () => hideVTModal(false));
vtBtnConfirm.addEventListener('click', () => hideVTModal(true));

// 新建车站后检查是否需要建立虚拟换乘（异步）
async function checkAndPromptVirtualTransfer(newStationId) {
  const newSt = state.stations.find(s => s.id === newStationId);
  if (!newSt) return;

  // 排除同一条线上的所有其他车站（同线路已通过轨道连接，无需虚拟换乘）
  const sameLineStations = new Set();
  state.lines.forEach(line => {
    if (line.stationIds.includes(newStationId)) {
      line.stationIds.forEach(sid => {
        if (sid !== newStationId) sameLineStations.add(sid);
      });
    }
  });

  // 查找1000m内的所有已有车站
  const candidates = [];
  for (const st of state.stations) {
    if (st.id === newStationId) continue;
    if (sameLineStations.has(st.id)) continue;
    // 已有换乘关系的不重复处理
    if (findVirtualTransfer(newStationId, st.id)) continue;

    const distKm = haversine(newSt.lat, newSt.lng, st.lat, st.lng);
    const distM = distKm * 1000;
    if (distM > 0 && distM <= 1000) {
      candidates.push({ station: st, distM });
    }
  }

  // 按距离排序，从近到远
  candidates.sort((a, b) => a.distM - b.distM);

  // 按站名去重：同名车站只弹出一次换乘提示（保留最近的）
  const seenNames = new Set();
  const dedupedCandidates = candidates.filter(c => {
    if (seenNames.has(c.station.name)) return false;
    seenNames.add(c.station.name);
    return true;
  });

  for (const c of dedupedCandidates) {
    const vtType = getVTTypeByDistance(c.distM);
    if (!vtType) continue;

    const confirmed = await showVTPrompt({
      stNameA: newSt.name,
      stNameB: c.station.name,
      distM: c.distM,
      vtType: vtType,
      mode: 'create',
    });

    if (confirmed) {
      // 非虚拟换乘（短/长通道、同台/节点）按现实口径视为同名换乘站；虚拟换乘保留两站站名。
      if (vtType && vtType.type !== 'virtual') {
        newSt.name = c.station.name;
        try { removeStationPolygons(newSt.id); renderStation(newSt); } catch(e) {}
      }
      // 与该站名下的所有同名车站都建立换乘关系
      const allSameName = candidates.filter(x => x.station.name === c.station.name);
      for (const target of allSameName) {
        const targetType = getVTTypeByDistance(target.distM);
        if (!targetType) continue;
        if (findVirtualTransfer(newStationId, target.station.id)) continue;
        state.virtualTransfers.push({
          stationA: newStationId,
          stationB: target.station.id,
          type: targetType.type,
          penaltyMin: targetType.penalty,
        });
      }
      // 确认后全部后台异步执行，不阻塞弹窗动画和后续弹窗
      setTimeout(() => { saveState(); invalidateFlowCache(); runSimulation(); }, 0);
    }
  }
}

// 移动车站后检查现有虚拟换乘是否需要更新（异步）
async function checkAndUpdateVirtualTransferOnMove(movedStationId) {
  const movedSt = state.stations.find(s => s.id === movedStationId);
  if (!movedSt) return;

  // 找出涉及此站的所有虚拟换乘
  const relatedVTs = [];
  for (let i = 0; i < state.virtualTransfers.length; i++) {
    const vt = state.virtualTransfers[i];
    if (vt.stationA === movedStationId || vt.stationB === movedStationId) {
      const otherId = vt.stationA === movedStationId ? vt.stationB : vt.stationA;
      const otherSt = state.stations.find(s => s.id === otherId);
      if (otherSt) {
        const distKm = haversine(movedSt.lat, movedSt.lng, otherSt.lat, otherSt.lng);
        const distM = distKm * 1000;
        relatedVTs.push({ index: i, vt, otherSt, distM });
      }
    }
  }

  for (const r of relatedVTs) {
    const oldType = VT_TYPES.find(t => t.type === r.vt.type);
    const oldMax = oldType ? oldType.maxDist : 1000;

    // 判断当前类型的容纳范围
    if (r.distM > oldMax) {
      // 超出了原有换乘方式的距离范围
      const newVTType = getVTTypeByDistance(r.distM);
      if (!newVTType) {
        // 超过1000m，取消换乘关系
        const confirmed = await showVTPrompt({
          stNameA: movedSt.name,
          stNameB: r.otherSt.name,
          distM: r.distM,
          vtType: { type: 'virtual', label: '超出范围', penalty: 0 },
          mode: 'remove',
        });
        if (confirmed) {
          state.virtualTransfers.splice(r.index, 1);
          setTimeout(() => { saveState(); invalidateFlowCache(); runSimulation(); }, 0);
        } else {
          // 用户拒绝取消，保持原状但记录可能不合理
        }
      } else {
        const confirmed = await showVTPrompt({
          stNameA: movedSt.name,
          stNameB: r.otherSt.name,
          distM: r.distM,
          vtType: newVTType,
          mode: 'upgrade',
        });
        if (confirmed) {
          r.vt.type = newVTType.type;
          r.vt.penaltyMin = newVTType.penalty;
          setTimeout(() => { saveState(); invalidateFlowCache(); runSimulation(); }, 0);
        }
      }  // end else (upgrade branch)
    }
    // 未超出范围则不变
  }
}

// 获取两条线路之间的换乘惩罚时间（分钟）
// 支线与主线之间换乘只需2分钟，其他线路间换乘为默认5分钟
// 虚拟换乘边的罚时已包含在边cost中，此处返回0
function getTransferPenalty(prevLineId, nextLineId) {
  if (!prevLineId || prevLineId === nextLineId) return 0;
  // 虚拟换乘边：罚时已在edge.cost中，不额外叠加
  if (prevLineId === VT_LINE_ID || nextLineId === VT_LINE_ID) return 0;
  const prevLine = state.lines.find(l => l.id === prevLineId);
  const nextLine = state.lines.find(l => l.id === nextLineId);
  if (!prevLine || !nextLine) return TRANSFER_PENALTY_MIN;
  // 检查是否为支线-主线关系（双向检查）
  const isBranchPair =
    (prevLine.parentLineId === nextLineId || nextLine.parentLineId === prevLineId) ||
    (prevLine.parentLineId && prevLine.parentLineId === nextLine.parentLineId);
  if (isBranchPair) {
    // 使用两者中较小的支线换乘时间
    const p1 = prevLine.branchTransferPenalty || TRANSFER_PENALTY_MIN;
    const p2 = nextLine.branchTransferPenalty || TRANSFER_PENALTY_MIN;
    return Math.min(p1, p2);
  }
  return TRANSFER_PENALTY_MIN;
}

function haversineKm(lat1, lng1, lat2, lng2) {
  const R = 6371;
  const dLat = (lat2 - lat1) * Math.PI / 180;
  const dLng = (lng2 - lng1) * Math.PI / 180;
  const a = Math.sin(dLat / 2) ** 2 + Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) * Math.sin(dLng / 2) ** 2;
  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
}

// Calculate actual path distance between two consecutive stations on a line,
// including all waypoints in between. This gives the real segment length
// rather than the straight-line (crow-flies) distance.
function getLineSegmentDistance(line, segIdx) {
  const sidA = line.stationIds[segIdx];
  const sidB = line.stationIds[segIdx + 1];
  const sa = state.stations.find(s => s.id === sidA);
  const sb = state.stations.find(s => s.id === sidB);
  if (!sa || !sb) return 0;

  const wps = (line.waypoints || []).filter(w => w.segIdx === segIdx).sort((a, b) => a.order - b.order);
  let total = 0;
  let prevLat = sa.lat, prevLng = sa.lng;
  for (const wp of wps) {
    total += haversineKm(prevLat, prevLng, wp.lat, wp.lng);
    prevLat = wp.lat;
    prevLng = wp.lng;
  }
  total += haversineKm(prevLat, prevLng, sb.lat, sb.lng);
  return total;
}

function buildWeightedGraph() {
  const graph = {};
  state.stations.forEach(s => { graph[s.id] = []; });
  state.lines.forEach(line => {
    const speed = line.speed || 80;
    for (let i = 0; i < line.stationIds.length - 1; i++) {
      const a = line.stationIds[i], b = line.stationIds[i + 1];
      const sa = state.stations.find(s => s.id === a);
      const sb = state.stations.find(s => s.id === b);
      if (!sa || !sb) continue;
      const distKm = getLineSegmentDistance(line, i);
      const timeMin = distKm / speed * 60;
      if (graph[a]) graph[a].push({ to: b, lineId: line.id, cost: timeMin, distKm, speed });
      if (graph[b]) graph[b].push({ to: a, lineId: line.id, cost: timeMin, distKm, speed });
    }
  });

  // 添加虚拟换乘边（不同车站之间的换乘通道）
  for (const vt of state.virtualTransfers) {
    if (!graph[vt.stationA] || !graph[vt.stationB]) continue;
    // 双向边：cost 即为换乘罚时
    graph[vt.stationA].push({
      to: vt.stationB,
      lineId: VT_LINE_ID,
      cost: vt.penaltyMin,
      distKm: 0,
      isVirtualTransfer: true,
    });
    graph[vt.stationB].push({
      to: vt.stationA,
      lineId: VT_LINE_ID,
      cost: vt.penaltyMin,
      distKm: 0,
      isVirtualTransfer: true,
    });
  }

  return graph;
}

function findRoute(fromId, toId) {
  const graph = buildWeightedGraph();
  if (!graph[fromId] || !graph[toId]) return null;

  // Dijkstra with transfer penalty: { node, cost, prevLine, path, linePath, distKm, transfers }
  const pq = [{ node: fromId, cost: 0, prevLine: null, path: [fromId], linePath: [], distKm: 0, transfers: 0 }];
  const best = new Map(); // key: "nodeId|prevLineId"
  best.set(fromId + '|_', 0);

  while (pq.length > 0) {
    let minIdx = 0;
    for (let i = 1; i < pq.length; i++) {
      if (pq[i].cost < pq[minIdx].cost) minIdx = i;
    }
    const cur = pq.splice(minIdx, 1)[0];

    if (cur.node === toId) {
      return { path: cur.path, linePath: cur.linePath, totalDistKm: cur.distKm, totalTimeMin: cur.cost, transfers: cur.transfers };
    }

    for (const edge of (graph[cur.node] || [])) {
      // 检查当前站是否禁用了在此线路间换乘
      if (cur.prevLine !== null && cur.prevLine !== edge.lineId && !edge.isVirtualTransfer) {
        const station = state.stations.find(s => s.id === cur.node);
        if (station && station._disabledTransferPairs) {
          const key = cur.prevLine < edge.lineId ? cur.prevLine + '_' + edge.lineId : edge.lineId + '_' + cur.prevLine;
          if (station._disabledTransferPairs[key]) continue;
        }
      }
      const transferPenalty = getTransferPenalty(cur.prevLine, edge.lineId);
      // 虚拟换乘边也算一次换乘（即使罚时在edge.cost中）
      const isVTTransfer = !!edge.isVirtualTransfer;
      const newCost = cur.cost + edge.cost + transferPenalty;
      const key = edge.to + '|' + edge.lineId;

      if (!best.has(key) || newCost < best.get(key)) {
        best.set(key, newCost);
        pq.push({
          node: edge.to,
          cost: newCost,
          prevLine: edge.lineId,
          path: [...cur.path, edge.to],
          linePath: [...cur.linePath, edge.lineId],
          distKm: cur.distKm + edge.distKm,
          transfers: cur.transfers + ((transferPenalty > 0 || isVTTransfer) ? 1 : 0)
        });
      }
    }
  }
  return null;
}

function pathToSegments(result) {
  if (!result || !result.path || result.path.length < 2) return [];
  const segments = [];
  for (let i = 0; i < result.path.length - 1; i++) {
    segments.push({ from: result.path[i], to: result.path[i + 1], lineId: result.linePath[i] || null });
  }
  return segments;
}

function showRouteOnMap(segments) {
  clearRouteOnMap();
  if (segments.length === 0) return;
  const stationNameMap = {};
  state.stations.forEach(s => { stationNameMap[s.id] = s.name; });

  // Build polylines grouped by line
  const allCoords = [];
  segments.forEach(seg => {
    const from = state.stations.find(s => s.id === seg.from);
    const to = state.stations.find(s => s.id === seg.to);
    if (from && to) {
      if (allCoords.length === 0) allCoords.push([from.lat, from.lng]);
      allCoords.push([to.lat, to.lng]);
    }
  });

  if (allCoords.length < 2) return;

  // Glowing route polyline
  navRouteLayer = L.layerGroup().addTo(map);

  // Outer glow
  L.polyline(allCoords, {
    color: '#4fc3f7', weight: 8, opacity: 0.25, lineCap: 'round',
  }).addTo(navRouteLayer);

  // Core line
  L.polyline(allCoords, {
    color: '#4fc3f7', weight: 3, opacity: 0.9, lineCap: 'round',
  }).addTo(navRouteLayer);

  // Animated dashes
  L.polyline(allCoords, {
    color: '#fff', weight: 2, opacity: 0.7, lineCap: 'round',
    dashArray: '8 16', dashOffset: '0',
    className: 'nav-dash-line',
  }).addTo(navRouteLayer);

  // Start & end markers
  const startS = state.stations.find(s => s.id === segments[0].from);
  const endS = state.stations.find(s => s.id === segments[segments.length - 1].to);
  if (startS) {
    L.circleMarker([startS.lat, startS.lng], {
      radius: 8, fillColor: '#00e676', color: '#fff', weight: 2, fillOpacity: 0.9,
    }).bindTooltip('起点: ' + startS.name, { direction: 'top' }).addTo(navRouteLayer);
  }
  if (endS) {
    L.circleMarker([endS.lat, endS.lng], {
      radius: 8, fillColor: '#ff1744', color: '#fff', weight: 2, fillOpacity: 0.9,
    }).bindTooltip('终点: ' + endS.name, { direction: 'top' }).addTo(navRouteLayer);
  }
}

function clearRouteOnMap() {
  if (navRouteLayer) { map.removeLayer(navRouteLayer); navRouteLayer = null; }
}

function formatRouteDisplay(result, segments) {
  const path = result.path;
  const stationNameMap = {};
  state.stations.forEach(s => { stationNameMap[s.id] = s.name; });
  const lineNameMap = {};
  state.lines.forEach(l => { lineNameMap[l.id] = l.name; });
  const lineSpeedMap = {};
  state.lines.forEach(l => { lineSpeedMap[l.id] = l.speed || 80; });

  let html = '';
  let currentLine = null;
  let legStart = 0;
  const lines = [];

  for (let i = 0; i < segments.length; i++) {
    if (segments[i].lineId !== currentLine) {
      if (currentLine && i > legStart) {
        lines.push({ lineId: currentLine, start: legStart, end: i });
      }
      currentLine = segments[i].lineId;
      legStart = i;
    }
  }
  if (currentLine && segments.length > legStart) {
    lines.push({ lineId: currentLine, start: legStart, end: segments.length });
  }

  // If no lines found or very short route, just show all stations
  if (lines.length === 0 && path.length >= 2) {
    html += '<div style="margin-bottom:4px;color:rgba(255,255,255,0.5)">直达</div>';
    html += path.map((sid, i) => {
      const name = stationNameMap[sid] || '?';
      return (i > 0 ? '<span class="leg-arrow">›</span>' : '') + '<b style="color:#fff">' + name + '</b>';
    }).join('');
    return html;
  }

  lines.forEach((leg, idx) => {
    const line = state.lines.find(l => l.id === leg.lineId);
    const lineColor = line ? line.color : '#999';
    const speed = lineSpeedMap[leg.lineId] || 80;
    html += '<div style="margin-bottom:6px">';
    html += '<span class="leg-line" style="background:' + lineColor + '">' + (lineNameMap[leg.lineId] || '?') + '</span>';
    html += '<span style="color:rgba(255,255,255,0.3);font-size:9px;margin-left:4px">' + speed + 'km/h</span>';
    if (idx > 0) html += '<span style="color:rgba(255,255,255,0.3);font-size:9px;margin-left:4px">(换乘)</span>';
    html += '<div style="margin-top:2px;padding-left:4px">';
    for (let i = leg.start; i <= leg.end; i++) {
      const sid = (i === leg.start) ? path[leg.start] : path[i];
      const name = stationNameMap[sid] || '?';
      if (i > leg.start) html += '<span class="leg-arrow">›</span>';
      if (i === leg.start || i === leg.end) {
        html += '<b style="color:#fff">' + name + '</b>';
      } else {
        html += '<span style="color:rgba(255,255,255,0.4)">' + name + '</span>';
      }
    }
    html += '</div></div>';
  });

  const distDisplay = result.totalDistKm >= 1
    ? result.totalDistKm.toFixed(1) + ' km'
    : (result.totalDistKm * 1000).toFixed(0) + ' m';
  const timeDisplay = result.totalTimeMin >= 60
    ? Math.floor(result.totalTimeMin / 60) + 'h' + Math.round(result.totalTimeMin % 60) + 'min'
    : Math.round(result.totalTimeMin) + ' min';
  html += '<div style="color:rgba(79,195,247,0.55);font-size:10px;margin-top:4px">';
  html += '共 ' + (path.length - 1) + ' 站 · ' + distDisplay + ' · ' + timeDisplay;
  if (result.transfers > 0) html += ' · 换乘 ' + result.transfers + ' 次';
  else html += ' · 无需换乘';
  html += '</div>';
  return html;
}

function populateNavLines() {
  const fromLine = document.getElementById('nav-from-line');
  const toLine = document.getElementById('nav-to-line');
  const prevFromLine = fromLine.value, prevToLine = toLine.value;

  const sorted = [...state.lines].sort((a, b) => {
    const na = parseInt(a.name), nb = parseInt(b.name);
    if (!isNaN(na) && !isNaN(nb)) return na - nb;
    return a.name.localeCompare(b.name, 'zh');
  });

  const opts = '<option value="">-- 线路 --</option>' + sorted.map(l =>
    '<option value="' + l.id + '">' + l.name + '</option>'
  ).join('');

  fromLine.innerHTML = opts;
  toLine.innerHTML = opts;
  if (prevFromLine) { fromLine.value = prevFromLine; onNavLineChange('from'); }
  if (prevToLine) { toLine.value = prevToLine; onNavLineChange('to'); }
}

function onNavLineChange(side) {
  const lineSel = document.getElementById('nav-' + side + '-line');
  const stationSel = document.getElementById('nav-' + side);
  const lineId = lineSel.value;
  const prevStation = stationSel.value;

  if (!lineId) {
    stationSel.innerHTML = '<option value="">先选线路</option>';
    stationSel.disabled = true;
    return;
  }

  const line = state.lines.find(l => l.id === lineId);
  if (!line) return;

  const stations = line.stationIds.map(id => state.stations.find(s => s.id === id)).filter(Boolean);
  const opts = '<option value="">-- 选择站点 --</option>' + stations.map(s =>
    '<option value="' + s.id + '">' + s.name + '</option>'
  ).join('');

  stationSel.innerHTML = opts;
  stationSel.disabled = false;
  if (prevStation && stations.some(s => s.id === prevStation)) stationSel.value = prevStation;
}

function openNavigation() {
  populateNavLines();
  document.getElementById('nav-overlay').classList.remove('hidden');
  document.getElementById('nav-route').innerHTML = '';
  clearRouteOnMap();
}

document.getElementById('btn-navigate').addEventListener('click', openNavigation);

// Cascade line → station for both sides
document.getElementById('nav-from-line').addEventListener('change', () => onNavLineChange('from'));
document.getElementById('nav-to-line').addEventListener('change', () => onNavLineChange('to'));

document.getElementById('nav-close').addEventListener('click', () => {
  document.getElementById('nav-overlay').classList.add('hidden');
  clearRouteOnMap();
});

document.getElementById('nav-overlay').addEventListener('click', (e) => {
  if (e.target === e.currentTarget) {
    document.getElementById('nav-overlay').classList.add('hidden');
    clearRouteOnMap();
  }
});

document.getElementById('nav-btn-swap').addEventListener('click', () => {
  const fromLine = document.getElementById('nav-from-line');
  const toLine = document.getElementById('nav-to-line');
  const from = document.getElementById('nav-from');
  const to = document.getElementById('nav-to');
  // Swap lines
  const tmpLine = fromLine.value;
  fromLine.value = toLine.value;
  toLine.value = tmpLine;
  // Cascade both sides
  onNavLineChange('from');
  onNavLineChange('to');
  // Wait for cascade then swap stations
  setTimeout(() => {
    const tmp = from.value; from.value = to.value; to.value = tmp;
  }, 0);
});

document.getElementById('nav-btn-find').addEventListener('click', () => {
  const fromId = document.getElementById('nav-from').value;
  const toId = document.getElementById('nav-to').value;
  const resultDiv = document.getElementById('nav-route');

  if (!fromId || !toId) {
    resultDiv.innerHTML = '<span style="color:rgba(255,255,255,0.3)">请选择起点和终点</span>';
    return;
  }
  if (fromId === toId) {
    resultDiv.innerHTML = '<span style="color:rgba(255,255,255,0.3)">起点和终点不能相同</span>';
    return;
  }

  const result = findRoute(fromId, toId);
  if (!result || !result.path || result.path.length < 2) {
    resultDiv.innerHTML = '<span style="color:#ef5350">未找到可行路径，请确认起终点是否在同一网络中</span>';
    clearRouteOnMap();
    return;
  }

  const segments = pathToSegments(result);
  resultDiv.innerHTML = formatRouteDisplay(result, segments);
  showRouteOnMap(segments);
});

document.getElementById('nav-btn-clear').addEventListener('click', () => {
  document.getElementById('nav-from-line').value = '';
  document.getElementById('nav-to-line').value = '';
  onNavLineChange('from');
  onNavLineChange('to');
  document.getElementById('nav-route').innerHTML = '';
  clearRouteOnMap();
});

// ==================== INIT ====================
updateUI();
runSimulation();

