// Convert all SHANGHAI_METRO coordinates from GCJ-02 → WGS-84 (fix China offset)
SHANGHAI_METRO.forEach(line => {
  line.stations.forEach(station => {
    const [wgsLng, wgsLat] = gcj02ToWgs84(station[2], station[1]);
    station[1] = wgsLat;
    station[2] = wgsLng;
  });
});

function loadDemo() {
  const stationMap = {}; // name → station object
  // First pass: collect all unique stations and count their occurrences (transfer count)
  const stationRefCount = {};
  SHANGHAI_METRO.forEach(lineData => {
    lineData.stations.forEach(([name, lat, lng]) => {
      if (!stationRefCount[name]) stationRefCount[name] = { count: 0, lat, lng };
      stationRefCount[name].count++;
    });
  });

  // Sort stations by transfer importance (more appearances = more central)
  const sortedNames = Object.keys(stationRefCount).sort((a, b) => {
    const diff = stationRefCount[b].count - stationRefCount[a].count;
    if (diff !== 0) return diff;
    return a.localeCompare(b);
  });

  // Assign data-driven populations from PVCGN distribution
  const totalStns = sortedNames.length;
  sortedNames.forEach((name, rank) => {
    const pop = populationByRank(rank + 1, totalStns);
    const { lat, lng } = stationRefCount[name];
    // 自动分配站点功能区类型
    let zone = guessZoneType(name);
    if (!zone) {
      // 按人口排名：前20%→business, 中间40%→commercial, 后40%→residential
      const ratio = rank / totalStns;
      zone = ratio < 0.15 ? 'office' : ratio < 0.5 ? 'shopping' : 'residential';
    }
    const station = {
      id: genId(),
      name, lat, lng,
      population: pop,
      zoneType: zone,
    };
    state.stations.push(station);
    renderStation(station);
    stationMap[name] = station;
  });

  // Second pass: create lines
  SHANGHAI_METRO.forEach(lineData => {
    const stationIds = lineData.stations
      .map(([name]) => stationMap[name].id);
    createLine(stationIds);
    const line = state.lines[state.lines.length - 1];
    line.name = lineData.name;
    line.color = lineData.color;
    if (linePolylines[line.id]) {
      linePolylines[line.id].setStyle({ color: lineData.color });
    }
  });
  state.currentLineId = null;
  // 统一刷新所有站台（兜底 circleMarker + 线路多边形）
  refreshAllStations();
  invalidateFlowCache();
  updateUI();
  runSimulation();
  saveState();
  fitMapToStations();
  initAllTrains();
  // 页面加载即启动模拟，列车立刻开始运行
  startSimulation();
}

// v51: 默认不再加载上海示范线网，也不自动读取本地存档。
// 目标：玩家点击“上海”后只看到上海底图；只有手动导入/读取存档时才恢复车站和线路。
