  try { hideCurrentLineNodes(); } catch(e) {}
  try {
    Object.values(stationTransferPolygons || {}).forEach(arr => (arr || []).forEach(p => { try { map.removeLayer(p); } catch(e) {} }));
    Object.values(linePolylines || {}).forEach(p => { try { map.removeLayer(p); } catch(e) {} });
    Object.values(waypointMarkers || {}).forEach(m => { try { map.removeLayer(m); } catch(e) {} });
    Object.values(trainMarkers || {}).forEach(m => { try { map.removeLayer(m); } catch(e) {} });
  } catch(e) {}
  stationMarkers = {};
  stationTransferPolygons = {};
  linePolylines = {};
  waypointMarkers = {};
  trainMarkers = {};
