;/* ===== bundled module: js/legacy/20-operation-config.js ===== */
/* Extracted from original index.html during low-risk modular refactor. Execution order is preserved. */
window.CITYRAIL_OPERATION_CONFIG = {
  targetLoadFactor: 0.82,
  reserveTrainRatio: 0.15,
  dwellBase: 28,
  dwellPerPassenger: 0.012,
  crushCapacityFactor: 1.25,
  realtimeHeadwayControl: true,
  automaticShortTurn: true,
  congestionDispatchBoost: true,
  maxHeadwayDeviation: 0.18,
  peakPassengerMultiplier: 0.18,
  cbdMultiplier: 2.4,
  transferStationMultiplier: 1.9
};

window.computeAdaptiveHeadway = function(line, demand){
   const base = line.headway || 180;
   if(demand > 0.9) return Math.max(90, base * 0.72);
   if(demand > 0.7) return Math.max(120, base * 0.85);
   if(demand < 0.3) return base * 1.2;
   return base;
};

window.computeRequiredFleet = function(roundTripSec, headwaySec){
   return Math.ceil(roundTripSec / headwaySec);
};

window.computeDynamicDwell = function(boarding, alighting){
   const cfg = window.CITYRAIL_OPERATION_CONFIG;
   return cfg.dwellBase + (boarding + alighting) * cfg.dwellPerPassenger;
};

window.applyShanghaiPassengerBoost = function(station){
   if(!station) return 1;
   let m = 1;
   if(station.zoneType === 'business') m *= 2.2;
   if(station.zoneType === 'commercial') m *= 1.7;
   if(station.zoneType === 'hub') m *= 2.5;
   if(station.isTransfer) m *= 1.5;
   return m * (window.CITYRAIL_OPERATION_CONFIG.peakPassengerMultiplier || 1);
};

