;/* ===== bundled module: js/legacy/96-service-start-v17.js ===== */
/* CityRail v17: service-day startup model.
   - Default operating clock starts at 05:30.
   - A line's stations open for passenger entry 15 minutes before that line's firstTrain.
   - Trains are not created before firstTrain.
   - At firstTrain, the fleet is placed evenly by station using the existing balanced initializer.
   - Terminal auto-spawn is blocked until the line has been activated, preventing early bunching. */
(function(){
  'use strict';

  const PREOPEN_MIN = 15;
  const EPS = 0.02;

  function num(v, d){
    const n = Number(v);
    return Number.isFinite(n) ? n : (d || 0);
  }
  function nowSec(){ return num(window.state && state.simulationHour, 0) * 3600; }
  function firstSec(line){ return num(line && line.firstTrain, 6) * 3600; }
  function lastSec(line){ return num(line && line.lastTrain, 22) * 3600; }
  function preOpenSec(line){ return Math.max(0, firstSec(line) - PREOPEN_MIN * 60); }
  function lineInPreopenOrService(line){
    const t = nowSec();
    return !!line && t + EPS >= preOpenSec(line) && t < lastSec(line);
  }
  function lineInService(line){
    const t = nowSec();
    return !!line && t + EPS >= firstSec(line) && t < lastSec(line);
  }
  function getLine(lineId){
    return window.state && Array.isArray(state.lines) ? state.lines.find(l => l.id === lineId) : null;
  }
  function stationOpen(stationId){
    if(!window.state || !Array.isArray(state.lines)) return true;
    for(const line of state.lines){
      if(!line || !Array.isArray(line.stationIds)) continue;
      if(line.stationIds.indexOf(stationId) < 0) continue;
      if(lineInPreopenOrService(line)) return true;
    }
    return false;
  }
  function hasActiveTrainOnLine(lineId){
    return !!(window.state && Array.isArray(state.trains) && state.trains.some(t => t && t.lineId === lineId && t.state !== 'done'));
  }
  function activateLineService(line, reason){
    if(!line || !Array.isArray(line.stationIds) || line.stationIds.length < 2) return false;
    if(!lineInService(line)) return false;
    if(line._serviceActivatedV17 && hasActiveTrainOnLine(line.id)) return false;

    // Clear any stale early-spawn/partial trains for this line before using the balanced initializer.
    if(window.state && Array.isArray(state.trains)){
      state.trains = state.trains.filter(t => {
        if(!t || t.lineId !== line.id) return true;
        try{
          if(window.trainMarkers && trainMarkers[t.id] && window.map){
            map.removeLayer(trainMarkers[t.id]);
            delete trainMarkers[t.id];
          }
        }catch(e){}
        return false;
      });
    }

    line._serviceActivatedV17 = true;
    line._serviceActivationReasonV17 = reason || 'first_train';
    line._serviceActivatedAtSecV17 = nowSec();

    try{
      if(typeof window.initTrainsForLine === 'function') window.initTrainsForLine(line);
      else if(typeof initTrainsForLine === 'function') initTrainsForLine(line);
    }catch(e){
      console.warn('[CityRail v17] failed to activate line service', line && (line.name || line.id), e);
      return false;
    }

    // The balanced initializer creates a full fleet in distributed positions. Align strict schedule to the next headway.
    try{
      const headway = typeof getCurrentHeadway === 'function' ? Math.max(30, num(getCurrentHeadway(line), 180)) : Math.max(30, num(line.normalHeadwayMin, 6) * 60);
      const t = nowSec();
      line._dispatchReady = true;
      line._strictSchedule = line._strictSchedule || {};
      line._strictSchedule.fwdNext = t + headway;
      line._strictSchedule.bwdNext = t + headway / 2;
      line._strictSchedule.lastHeadway = headway;
      line._lastFwdDispatch = t;
      line._lastBwdDispatch = t;
    }catch(e){}

    try{ if(typeof renderAllTrainMarkers === 'function') renderAllTrainMarkers(); }catch(e){}
    return true;
  }

  // Keep clock visually aligned with the new default when opening a fresh game.
  try{
    if(window.state && Math.abs(num(state.simulationHour, 0) - 6) < 0.001){
      state.simulationHour = 5.5;
    }
    const slider = document.getElementById('time-slider');
    const label = document.getElementById('time-label');
    if(slider && Math.abs(num(slider.value, 0) - 8) < 0.001) slider.value = '5.5';
    if(label && (label.textContent || '').trim() === '08:00') label.textContent = '05:30';
  }catch(e){}

  // Passenger creation gate: before a station's pre-open time, it cannot accept passenger entry.
  // Returning count=0 avoids accidentally counting unopened demand as delivered.
  try{
    if(typeof createPassengerBatch === 'function' && !createPassengerBatch.__serviceStartV17){
      const originalCreatePassengerBatch = createPassengerBatch;
      const wrappedCreatePassengerBatch = function(originId, destId, count){
        if(!stationOpen(originId)){
          return {
            id: 'blocked_v17_' + Date.now() + '_' + Math.floor(Math.random()*9999),
            originId,
            destinationId: destId,
            legs: [],
            currentLeg: 0,
            state: 'arrived',
            trainId: null,
            count: 0,
            _blockedByServiceStartV17: true
          };
        }
        return originalCreatePassengerBatch.apply(this, arguments);
      };
      wrappedCreatePassengerBatch.__serviceStartV17 = true;
      window.createPassengerBatch = wrappedCreatePassengerBatch;
      createPassengerBatch = wrappedCreatePassengerBatch;
    }
  }catch(e){
    console.warn('[CityRail v17] passenger pre-open gate failed', e);
  }



  // During 05:30 → firstTrain, no trains exist, so the train animation loop would normally
  // skip generatePassengers(). Generate pre-open station demand once per simulation minute here.
  try{
    if(typeof runSimulation === 'function' && !runSimulation.__serviceStartV17){
      const originalRunSimulation = runSimulation;
      const wrappedRunSimulation = function(){
        const ret = originalRunSimulation.apply(this, arguments);
        try{
          const noActiveTrains = !window.state || !Array.isArray(state.trains) || !state.trains.some(t => t && t.state !== 'done');
          if(window.state && state.isSimulating && noActiveTrains && typeof generatePassengers === 'function'){
            generatePassengers(60); // one game minute; createPassengerBatch gate limits it to pre-open stations only
          }
        }catch(e){}
        return ret;
      };
      wrappedRunSimulation.__serviceStartV17 = true;
      window.runSimulation = wrappedRunSimulation;
      runSimulation = wrappedRunSimulation;
    }
  }catch(e){ console.warn('[CityRail v17] pre-open passenger generator failed', e); }

  // Block strict terminal spawning before a line's service has been activated.
  try{
    const previousCanSpawn = window.cityrailCanSpawnTerminalTrain;
    window.cityrailCanSpawnTerminalTrain = function(line, dir){
      if(!line) return false;
      if(!lineInService(line)) return false;
      if(!line._serviceActivatedV17 && !hasActiveTrainOnLine(line.id)) return false;
      if(typeof previousCanSpawn === 'function') return previousCanSpawn(line, dir);
      return true;
    };
  }catch(e){}

  // Override dispatch loop: first activate each line exactly when its firstTrain time arrives,
  // then delegate to the existing strict headway dispatcher.
  try{
    const originalDispatch = typeof dispatchLoop === 'function' ? dispatchLoop : window.dispatchLoop;
    const wrappedDispatch = function(){
      if(!window.state || !state.isSimulating || !Array.isArray(state.lines)) return;
      for(const line of state.lines){
        if(!line || !Array.isArray(line.stationIds) || line.stationIds.length < 2) continue;
        if(lineInService(line) && (!line._serviceActivatedV17 || !hasActiveTrainOnLine(line.id))){
          activateLineService(line, 'dispatch_first_train');
        }
      }
      if(typeof originalDispatch === 'function') return originalDispatch.apply(this, arguments);
    };
    wrappedDispatch.__serviceStartV17 = true;
    window.dispatchLoop = wrappedDispatch;
    dispatchLoop = wrappedDispatch;
  }catch(e){
    console.warn('[CityRail v17] dispatch wrapper failed', e);
  }

  // Patch initAllTrains behavior indirectly: if called before a line's first train, the modified
  // initTrainsForLine in 10-core returns no train. This timer is a safety net for pause/slider cases.
  setInterval(function(){
    try{
      if(!window.state || !Array.isArray(state.lines)) return;
      for(const line of state.lines){
        if(lineInService(line) && (!line._serviceActivatedV17 || !hasActiveTrainOnLine(line.id))){
          activateLineService(line, 'service_timer');
        }
      }
    }catch(e){ console.warn('[CityRail v17] service activation timer failed', e); }
  }, 800);

  window.CityRailServiceStartV17 = {
    stationOpen,
    lineInService,
    lineInPreopenOrService,
    activateLineService,
    preOpenMinutes: PREOPEN_MIN
  };
})();

