;/* ===== bundled module: js/features/save/save-service.js ===== */
/* CityRail Feature: Save Service v2 */
(function (window) {
  'use strict';

  window.CityRail.register('save-service', function (CityRail) {
    const STORAGE_KEY = 'cityrail.save.autoslot.v2';
    const VERSION = 2;
    const KEEP_UNDERSCORE_KEYS = new Set([
      '_totalDelivered', '_totalGenerated', '_lineRidership', '_segmentActualFlow', '_exitFlow', '_fareRevenueYuan'
    ]);

    function sanitize(value) {
      const seen = new WeakSet();
      return JSON.parse(JSON.stringify(value, function (key, val) {
        if (typeof val === 'function') return undefined;
        if (val && typeof val === 'object') {
          if (seen.has(val)) return undefined;
          seen.add(val);
        }
        if (/^(marker|layer|polyline|tooltip|popup|icon|element|el|map)$/i.test(key)) return undefined;
        if (key && key[0] === '_' && !KEEP_UNDERSCORE_KEYS.has(key)) return undefined;
        return val;
      }));
    }

    function buildSnapshot(meta) {
      const st = CityRail.state.get();
      return {
        schema: 'cityrail-save',
        version: VERSION,
        createdAt: new Date().toISOString(),
        meta: Object.assign({ source: 'save-service-v2' }, meta || {}),
        state: sanitize({
          stations: st.stations || [],
          lines: st.lines || [],
          virtualTransfers: st.virtualTransfers || [],
          simulationHour: st.simulationHour,
          simSpeed: st.simSpeed,
          isSimulating: false,
          showTrains: st.showTrains,
          stationWaitingPool: st.stationWaitingPool || {},
          batches: st.batches || [],
          trains: st.trains || [],
          _totalDelivered: st._totalDelivered || 0,
          _totalGenerated: st._totalGenerated || 0,
          _lineRidership: st._lineRidership || {},
          _segmentActualFlow: st._segmentActualFlow || {},
          _exitFlow: st._exitFlow || {},
          _fareRevenueYuan: st._fareRevenueYuan || 0
        }),
        config: sanitize({
          SH_REALISM_CONFIG: window.SH_REALISM_CONFIG || null,
          CITYRAIL_OPERATION_CONFIG: window.CITYRAIL_OPERATION_CONFIG || null
        })
      };
    }

    function applySnapshot(snapshot) {
      if (!snapshot || !snapshot.state) throw new Error('存档文件无效：缺少 state');
      CityRail.legacy.pauseSimulation();
      const next = sanitize(snapshot.state);
      const target = CityRail.state.get();
      Object.assign(target, next, { isSimulating: false });
      CityRail.state.bind(target);
      if (snapshot.config && snapshot.config.CITYRAIL_OPERATION_CONFIG) {
        window.CITYRAIL_OPERATION_CONFIG = snapshot.config.CITYRAIL_OPERATION_CONFIG;
      }
      CityRail.legacy.refreshAll();
      CityRail.events.emit('save:loaded', { snapshot });
      return true;
    }

    function saveLocal(name) {
      const snapshot = buildSnapshot({ name: name || 'autoslot' });
      localStorage.setItem(STORAGE_KEY, JSON.stringify(snapshot));
      CityRail.events.emit('save:written', { snapshot, storageKey: STORAGE_KEY });
      return snapshot;
    }

    function loadLocal() {
      const raw = localStorage.getItem(STORAGE_KEY) || localStorage.getItem('cityrail.save.autoslot.v1');
      if (!raw) throw new Error('没有找到本地存档');
      return applySnapshot(JSON.parse(raw));
    }

    function exportSnapshot(filename) {
      const snapshot = buildSnapshot({ name: filename || 'manual-export' });
      const blob = new Blob([JSON.stringify(snapshot, null, 2)], { type: 'application/json;charset=utf-8' });
      const a = document.createElement('a');
      a.href = URL.createObjectURL(blob);
      a.download = (filename || 'cityrail-save') + '.json';
      document.body.appendChild(a);
      a.click();
      setTimeout(function () { URL.revokeObjectURL(a.href); a.remove(); }, 0);
      return snapshot;
    }

    function importFile(file) {
      return new Promise(function (resolve, reject) {
        const reader = new FileReader();
        reader.onload = function () {
          try { resolve(applySnapshot(JSON.parse(String(reader.result || '{}')))); }
          catch (error) { reject(error); }
        };
        reader.onerror = reject;
        reader.readAsText(file, 'utf-8');
      });
    }

    const api = { version: VERSION, storageKey: STORAGE_KEY, buildSnapshot, applySnapshot, saveLocal, loadLocal, exportSnapshot, importFile };
    window.CityRailSave = api;
    return api;
  }, { order: 100 });
})(window);

;

;/* ===== bundled module: js/features/save/save-panel.js ===== */
/* CityRail Feature: Save Panel - integrated into Settings secondary menu */
(function (window, document) {
  'use strict';

  window.CityRail.register('save-panel', function (CityRail) {
    function toast(message) {
      let el = document.getElementById('cityrail-toast');
      if (!el) {
        el = document.createElement('div');
        el.id = 'cityrail-toast';
        el.className = 'cityrail-floating-toast';
        document.body.appendChild(el);
      }
      el.textContent = message;
      el.classList.add('show');
      clearTimeout(el.__timer);
      el.__timer = setTimeout(function () { el.classList.remove('show'); }, 1800);
    }


    function showInfoModal(title, lines) {
      let modal = document.getElementById('cityrail-info-modal');
      if (!modal) {
        modal = document.createElement('div');
        modal.id = 'cityrail-info-modal';
        modal.style.cssText = 'position:fixed;inset:0;z-index:99999;background:rgba(0,0,0,.48);display:flex;align-items:center;justify-content:center;padding:20px;';
        modal.innerHTML = '<div style="width:min(720px,92vw);max-height:78vh;overflow:auto;background:#111827;color:#f9fafb;border:1px solid rgba(255,255,255,.16);border-radius:16px;box-shadow:0 24px 80px rgba(0,0,0,.45);padding:20px 22px;">'
          + '<div style="display:flex;align-items:center;justify-content:space-between;gap:16px;margin-bottom:12px;">'
          + '<h2 data-role="title" style="margin:0;font-size:18px;font-weight:700;"></h2>'
          + '<button type="button" data-role="close" style="border:0;border-radius:10px;padding:6px 10px;background:rgba(255,255,255,.12);color:#fff;cursor:pointer;">关闭</button>'
          + '</div><div data-role="body" style="font-size:13px;line-height:1.8;color:rgba(255,255,255,.86);"></div></div>';
        document.body.appendChild(modal);
        modal.addEventListener('click', function(e){
          if (e.target === modal || (e.target && e.target.getAttribute('data-role') === 'close')) modal.style.display = 'none';
        });
      }
      modal.querySelector('[data-role="title"]').textContent = title;
      modal.querySelector('[data-role="body"]').innerHTML = lines.map(function(x){ return '<p style="margin:0 0 8px;">' + x + '</p>'; }).join('');
      modal.style.display = 'flex';
    }

    function showChangelog() {
      showInfoModal('更新日志', [
        '<b>v64</b>：线路长度前加“总线网长度”；设置面板删除“存档与诊断”标题和箭头；新增 Englishi Mode 开关。',
        '<b>v63</b>：修复时间显示归一化，xx:60 自动进位为下一小时 xx:00；设置面板中“导出/导入”按钮替换为“更新日志/常见问题”。',
        '<b>v62</b>：清理旧折返/车头调试模块；控制中心新增线网总长度；进站客流改为全网总客流口径。',
        '<b>v61</b>：终点折返改为独立状态机，避免列车在终点站长期停靠不折返。',
        '<b>v59</b>：既有线路增减节点/车站后，统一重建线路拓扑、地图路径和列车运行路径。'
      ]);
    }

    function showFaq() {
      showInfoModal('常见问题', [
        '<b>为什么点击上海后没有线路？</b><br>当前版本默认只显示上海底图。只有手动画线或读取本地存档后，车站和线路才会出现。',
        '<b>为什么设置里没有导入/导出按钮？</b><br>按 v63 要求，原位置已替换为更新日志和常见问题。现有本地保存/读取仍保留。',
        '<b>全网总客流怎么算？</b><br>旅客一进入车站候车池就累计，不等上车或出站。',
        '<b>线网总长度怎么算？</b><br>按当前所有线路的真实路径节点累计，增减车站或节点后会自动重算。'
      ]);
    }

    function createPanel() {
      if (document.getElementById('cityrail-save-panel')) return;
      const settingsPanel = document.getElementById('settings-panel');
      if (!settingsPanel) return;

      const divider = settingsPanel.querySelector('.settings-divider');
      const panel = document.createElement('div');
      panel.id = 'cityrail-save-panel';
      panel.className = 'cityrail-save-panel cityrail-save-panel-in-settings';
      panel.innerHTML = [
        '<div class="cityrail-save-submenu cityrail-save-submenu-flat">',
          '<button type="button" data-act="save">保存</button>',
          '<button type="button" data-act="load">读取</button>',
          '<button type="button" data-act="export">导出</button>',
          '<button type="button" data-act="import">导入</button>',
          '<button type="button" data-act="changelog">更新日志</button>',
          '<button type="button" data-act="faq">常见问题</button>',
        '</div>',
        '<div class="settings-row cityrail-english-mode-row" data-act="english-mode">',
          '<span class="sr-label">Englishi Mode</span>',
          '<div class="settings-toggle off" id="st-english-mode"></div>',
        '</div>',
        '<input type="file" accept="application/json" hidden>'
      ].join('');

      if (divider && divider.parentNode) divider.parentNode.insertBefore(panel, divider);
      else settingsPanel.appendChild(panel);

      const input = panel.querySelector('input');
      const submenu = panel.querySelector('.cityrail-save-submenu');
      const englishToggle = panel.querySelector('#st-english-mode');
      function syncEnglishModeToggle() {
        const on = localStorage.getItem('cityrail_englishi_mode') === '1';
        if (englishToggle) englishToggle.className = 'settings-toggle ' + (on ? 'on' : 'off');
        document.body.classList.toggle('cityrail-englishi-mode', on);
      }
      syncEnglishModeToggle();

      panel.addEventListener('click', function (event) {
        const btn = event.target && event.target.closest && event.target.closest('[data-act]');
        if (!btn || !panel.contains(btn)) return;
        const act = btn.getAttribute('data-act');
        event.stopPropagation();
        try {
          if (act === 'english-mode') {
            const on = localStorage.getItem('cityrail_englishi_mode') === '1';
            localStorage.setItem('cityrail_englishi_mode', on ? '0' : '1');
            syncEnglishModeToggle();
            toast(on ? 'Englishi Mode 已关闭' : 'Englishi Mode 已开启');
            return;
          }
          if (act === 'save') { CityRailSave.saveLocal(); toast('已保存到本地'); }
          if (act === 'load') { CityRailSave.loadLocal(); toast('已读取存档'); }
          if (act === 'export') { CityRailSave.exportSnapshot('cityrail-save-' + new Date().toISOString().slice(0,10)); toast('已导出存档文件'); }
          if (act === 'import') { input && input.click(); return; }
          if (act === 'changelog') showChangelog();
          if (act === 'faq') showFaq();
        } catch (error) {
          console.error(error);
          toast(error.message || '操作失败');
        }
      });

      input.addEventListener('change', function () {
        const file = input.files && input.files[0];
        if (!file) return;
        CityRailSave.importFile(file)
          .then(function () { toast('导入完成'); })
          .catch(function (error) { console.error(error); toast(error.message || '导入失败'); })
          .finally(function () { input.value = ''; });
      });
    }

    return { start: createPanel, toast };
  }, { order: 110 });
})(window, document);

