;/* ===== bundled module: js/features/od-icons/od-icons.js ===== */
(function(){
  'use strict';

  const NS = 'CityRailODIcons';
  const TOP_N = 18;
  const UPDATE_MS = 4500;
  let layer = null;
  let enabled = false;
  let timer = null;
  let lastRenderAt = 0;

  function getRuntime(){
    const st = (window.CityRail && window.CityRail.state && window.CityRail.state.get && window.CityRail.state.get()) || window.state;
    let leafletMap = null;
    try { if (typeof map !== 'undefined') leafletMap = map; } catch(e) {}
    return { st, leafletMap };
  }

  function getODCache(){
    try {
      if (typeof odMatrixCache !== 'undefined' && odMatrixCache && odMatrixCache.matrix && odMatrixCache.stations) return odMatrixCache;
    } catch(e) {}
    try {
      if (typeof buildODMatrix === 'function') return buildODMatrix();
    } catch(e) {}
    return null;
  }

  function ensureLayer(){
    const { leafletMap } = getRuntime();
    if (!leafletMap || !window.L) return null;
    if (!layer) layer = L.layerGroup();
    if (!leafletMap.hasLayer(layer)) layer.addTo(leafletMap);
    return layer;
  }

  function clear(){
    if (layer) layer.clearLayers();
  }

  function stationLatLng(station){
    if (!station) return null;
    const lat = Number(station.lat), lng = Number(station.lng);
    if (!Number.isFinite(lat) || !Number.isFinite(lng)) return null;
    return [lat, lng];
  }

  function getTopPairs(cache){
    if (!cache || !cache.matrix || !cache.stations) return [];
    const stations = cache.stations;
    const pairs = [];

    // Prefer the v9 active-pair cache because it is already filtered and sorted by OD weight.
    if (Array.isArray(cache._activePairsV9) && cache._activePairsV9.length) {
      for (let k = 0; k < cache._activePairsV9.length && pairs.length < TOP_N * 4; k++) {
        const p = cache._activePairsV9[k];
        const o = stations[p[0]], d = stations[p[1]];
        const val = Number(p[2] || 0);
        if (o && d && val > 0) pairs.push({ origin: o, dest: d, value: val });
      }
    } else {
      const m = cache.matrix;
      for (let i = 0; i < stations.length; i++) {
        for (let j = 0; j < stations.length; j++) {
          if (i === j) continue;
          const val = Number((m[i] && m[i][j]) || 0);
          if (val > 0) pairs.push({ origin: stations[i], dest: stations[j], value: val });
        }
      }
      pairs.sort((a,b)=>b.value-a.value);
    }

    // Avoid showing too many almost-identical arrows from/to the same station. This keeps the map readable.
    const outCount = Object.create(null);
    const inCount = Object.create(null);
    const selected = [];
    for (const p of pairs) {
      if (!p.origin || !p.dest || p.origin.id === p.dest.id) continue;
      const okOut = (outCount[p.origin.id] || 0) < 3;
      const okIn = (inCount[p.dest.id] || 0) < 3;
      if (!okOut || !okIn) continue;
      selected.push(p);
      outCount[p.origin.id] = (outCount[p.origin.id] || 0) + 1;
      inCount[p.dest.id] = (inCount[p.dest.id] || 0) + 1;
      if (selected.length >= TOP_N) break;
    }
    return selected;
  }

  function shortCount(v){
    v = Math.max(0, Number(v || 0));
    if (v >= 10000) return (v / 10000).toFixed(v >= 100000 ? 0 : 1) + '万';
    if (v >= 1000) return (v / 1000).toFixed(v >= 10000 ? 0 : 1) + 'k';
    return String(Math.round(v));
  }

  function makeBadge(kind, text, title){
    return L.divIcon({
      className: 'od-icon-wrapper',
      html: '<div class="od-icon od-icon-' + kind + '" title="' + escapeHtml(title || '') + '">' + escapeHtml(text) + '</div>',
      iconSize: [28, 28],
      iconAnchor: [14, 14]
    });
  }

  function escapeHtml(s){
    return String(s == null ? '' : s).replace(/[&<>"]/g, function(ch){
      return ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;'}[ch]);
    });
  }

  function drawPair(p, maxVal){
    const group = ensureLayer();
    if (!group || !window.L) return;
    const a = stationLatLng(p.origin), b = stationLatLng(p.dest);
    if (!a || !b) return;
    const weightRatio = maxVal > 0 ? Math.max(0.2, Math.min(1, p.value / maxVal)) : 0.5;
    const weight = 2 + Math.round(weightRatio * 5);
    const opacity = 0.28 + weightRatio * 0.45;
    const title = (p.origin.name || '起点') + ' → ' + (p.dest.name || '终点') + '：' + shortCount(p.value);

    L.polyline([a, b], {
      className: 'od-flow-line',
      color: '#f59e0b',
      weight: weight,
      opacity: opacity,
      dashArray: '7 8',
      interactive: false,
      pane: 'overlayPane'
    }).addTo(group);

    const mid = [(a[0] + b[0]) / 2, (a[1] + b[1]) / 2];
    L.marker(a, { icon: makeBadge('origin', '出', '主要出发站：' + (p.origin.name || '')), interactive: false }).addTo(group);
    L.marker(b, { icon: makeBadge('dest', '到', '主要到达站：' + (p.dest.name || '')), interactive: false }).addTo(group);
    L.marker(mid, { icon: makeBadge('flow', shortCount(p.value), title), interactive: false }).addTo(group);
  }

  function render(force){
    if (!enabled) return;
    const now = Date.now();
    if (!force && now - lastRenderAt < UPDATE_MS) return;
    lastRenderAt = now;
    const group = ensureLayer();
    if (!group) return;
    group.clearLayers();
    const cache = getODCache();
    const pairs = getTopPairs(cache);
    if (!pairs.length) return;
    const maxVal = Math.max.apply(null, pairs.map(p => Number(p.value || 0)));
    pairs.forEach(p => drawPair(p, maxVal));
  }

  function setEnabled(on){
    enabled = !!on;
    const toggle = document.getElementById('st-od-icons');
    if (toggle) toggle.className = 'settings-toggle ' + (enabled ? 'on' : 'off');
    const row = document.querySelector('[data-setting="od-icons"]');
    if (row) row.classList.toggle('od-icons-enabled', enabled);
    if (enabled) {
      render(true);
      if (!timer) timer = setInterval(function(){ render(false); }, UPDATE_MS);
    } else {
      if (timer) { clearInterval(timer); timer = null; }
      clear();
    }
  }

  function installSettingsRow(){
    const panel = document.getElementById('settings-panel');
    if (!panel || document.getElementById('st-od-icons')) return;
    const divider = panel.querySelector('.settings-divider');
    const row = document.createElement('div');
    row.className = 'settings-row';
    row.setAttribute('data-setting', 'od-icons');
    row.innerHTML = '<span class="sr-label">显示 OD 流向图标</span><div class="settings-toggle off" id="st-od-icons"></div>';
    row.addEventListener('click', function(e){
      e.preventDefault();
      e.stopPropagation();
      setEnabled(!enabled);
    });
    if (divider && divider.parentNode) divider.parentNode.insertBefore(row, divider);
    else panel.appendChild(row);
  }

  function boot(){
    installSettingsRow();
    const { leafletMap } = getRuntime();
    if (leafletMap && leafletMap.on) {
      leafletMap.on('zoomend moveend', function(){ if (enabled) render(true); });
    }
  }

  window[NS] = {
    enable: function(){ setEnabled(true); },
    disable: function(){ setEnabled(false); },
    toggle: function(){ setEnabled(!enabled); },
    refresh: function(){ render(true); },
    isEnabled: function(){ return enabled; }
  };

  if (document.readyState === 'loading') document.addEventListener('DOMContentLoaded', boot);
  else boot();
})();

