    const lat2 = Number(b[0]), lng2 = Number(b[1]);
    const meanLat = ((lat1 + lat2) / 2) * Math.PI / 180;
    const x1 = lng1 * 111320 * Math.max(0.2, Math.cos(meanLat));
    const y1 = lat1 * 111320;
    const x2 = lng2 * 111320 * Math.max(0.2, Math.cos(meanLat));
    const y2 = lat2 * 111320;
    const dx = x2 - x1, dy = y2 - y1;
    const len = Math.hypot(dx, dy) || 1;
    const nx = -dy / len, ny = dx / len;
    function back(x, y){
      return [y / 111320, x / (111320 * Math.max(0.2, Math.cos(meanLat)))];
    }
    const o = Math.max(3, Number(offsetM) || CORRIDOR_OFFSET_M);
    const a1 = back(x1 + nx * o, y1 + ny * o);
    const b1 = back(x2 + nx * o, y2 + ny * o);
    const a2 = back(x1 - nx * o, y1 - ny * o);
