      try { if (window.CityRailODIcons && CityRailODIcons.refresh) CityRailODIcons.refresh(); } catch(e) {}
      try { if (window.CityRailTransferCorridors && CityRailTransferCorridors.refresh) CityRailTransferCorridors.refresh(); } catch(e) {}
