;/* ===== bundled module: js/legacy/112-time-and-menu-v63.js ===== */
/* CityRail v63 - time normalization + menu text finalizer
   1) Any display time generated from decimal hours must never show minute 60.
   2) Save/settings submenu uses 更新日志 and 常见问题 instead of 导出/导入.
*/
(function(){
  'use strict';
  function pad2(n){ return String(n).padStart(2,'0'); }
  function normalizeHour(hour){
    var total = Math.round((Number(hour) || 0) * 60);
    var day = ((total % 1440) + 1440) % 1440;
    return pad2(Math.floor(day / 60)) + ':' + pad2(day % 60);
  }
  window.cityrailFormatClockV63 = normalizeHour;

  function writeTimeLabels(){
    var st = window.state;
    if(!st) return;
    var t = normalizeHour(st.simulationHour);
    var ids = ['time-label','cct-time','metro-map-time'];
    for(var i=0;i<ids.length;i++){
      var el = document.getElementById(ids[i]);
      if(el) el.textContent = t;
    }
  }

  function finalizeMenu(){
    var panel = document.getElementById('cityrail-save-panel');
    if(!panel) return;
    var buttons = panel.querySelectorAll('[data-act]');
    buttons.forEach(function(btn){
      var act = btn.getAttribute('data-act');
      if(act === 'export') { btn.setAttribute('data-act','changelog'); btn.textContent = '更新日志'; }
      if(act === 'import') { btn.setAttribute('data-act','faq'); btn.textContent = '常见问题'; }
    });
  }

  function wrapRender(){
    if(!window.__CITYRAIL_DISABLE_LEGACY_CONTROL_CENTER__ && typeof window.renderCtrlCenter === 'function' && !window.renderCtrlCenter.__v63TimeNormalized){
      var old = window.renderCtrlCenter;
      window.renderCtrlCenter = function(){
        var r = old.apply(this, arguments);
        writeTimeLabels();
        return r;
      };
      window.renderCtrlCenter.__v63TimeNormalized = true;
    }
  }

  function tick(){
    try { wrapRender(); finalizeMenu(); writeTimeLabels(); } catch(e) {}
  }
  if(document.readyState === 'loading') document.addEventListener('DOMContentLoaded', tick);
  else setTimeout(tick, 0);
  setInterval(tick, 1000);
})();

;

