    const stableX=t=>{ const st=S(); const key=sid(t.id||t.trainId)+'|'+sid(lineId)+'|'+dir; st._atsTrainMotion=st._atsTrainMotion||{}; const raw=Math.max(left,Math.min(right,rawX(t))); const rec=st._atsTrainMotion[key]; let x=raw; if(rec){ const loop=raw<left+36&&rec.x>right-48; if(!loop&&raw<rec.x-10) x=rec.x; } st._atsTrainMotion[key]={x,raw,ts:Date.now()}; return x; };
    let svg=`<svg class="ats-v82-svg" width="${width}" height="${height}" viewBox="0 0 ${width} ${height}" preserveAspectRatio="xMinYMin meet"><defs><filter id="atsGlow"><feGaussianBlur stdDeviation="2.5" result="b"/><feMerge><feMergeNode in="b"/><feMergeNode in="SourceGraphic"/></feMerge></filter></defs>`;
    svg+=`<line class="ats-v82-mainline" x1="${left}" y1="${trackY}" x2="${right}" y2="${trackY}" stroke="${esc(color)}" stroke-width="8" opacity=".92"/><line x1="${left}" y1="${trackY+22}" x2="${right}" y2="${trackY+22}" stroke="rgba(255,255,255,.22)" stroke-width="2" stroke-dasharray="8 9"/>`;
    stations.forEach((it,i)=>{ const x=xOfSeq(i), sta=stationById(it.sid), name=sta?sta.name:`站点${it.idx+1}`; const w=stationLineWait(it.sid,line.id); svg+=`<circle cx="${x}" cy="${trackY}" r="8" fill="${esc(color)}" stroke="rgba(255,255,255,.9)" stroke-width="2"/><circle cx="${x}" cy="${trackY+22}" r="3" fill="${w>0?'#ffb340':'rgba(255,255,255,.30)'}"/><text class="ats-v82-station-name" x="${x}" y="${trackY-12}" text-anchor="middle">${esc(name)}</text><text class="ats-v101-wait ${w===0?'ats-v101-zero':''}" x="${x}" y="${trackY+44}" text-anchor="middle">${fmt(w)}人候车</text>`; if(i<total-1){ const sx=x+step*.5; svg+=`<text class="ats-v82-signal" x="${sx}" y="${trackY-12}" text-anchor="middle">●</text>`; } });
    const items=active.map(t=>({t,x:stableX(t),express:isExpress(t)})).sort((a,b)=>a.x-b.x); const locals=items.filter(x=>!x.express); locals.forEach((it,i)=>{ const prev=locals[i-1]; it.lane=(prev&&Math.abs(it.x-prev.x)<48)?(prev.lane===0?1:0):0; }); items.filter(x=>x.express).forEach(x=>x.lane=2);
    items.forEach(it=>{ const t=it.t, y=it.express?trackY-86:trackY-36-it.lane*24, stateColor=it.express?'#0a84ff':(isRed(t)?'#ff453a':'#32d74b'), fill=it.express?'rgba(10,132,255,.22)':(isRed(t)?'rgba(255,69,58,.20)':'rgba(50,215,75,.18)'); svg+=`<g class="ats-v82-train ${it.express?'ats-v82-express-train':''}" transform="translate(${it.x},${y})"><rect x="-23" y="-10" width="46" height="20" rx="6" fill="${fill}" stroke="${stateColor}" stroke-width="2.4" filter="url(#atsGlow)"/><text class="ats-v82-train-load" x="0" y="4" text-anchor="middle">${Math.max(0,Math.round(num(t.load)))}</text></g>`; });
    svg+='</svg>';
